def get_citations(title, citations):
    title_norm = title.lower().replace(".txt", "").strip()
    for c in citations:
        c_title_norm = c['title'].lower().strip()
        if title_norm == c_title_norm:
            return int(c['citation_count'])
    return 0

with open(locals()['var_function-call-10773655256875707708'], 'r') as f:
    papers = json.load(f)

results = []
total_chi = 0

for p in papers:
    fn = p['filename']
    txt = p['text']

    is_chi = False
    is_ubicomp = False

    header_footer = txt[:2500] + "\n" + txt[-2500:]

    if "UBICOMP" in header_footer.upper():
        is_ubicomp = True

    if "Conference on Human Factors" in header_footer:
        is_chi = True
    if "CHI 20" in header_footer or "CHI 19" in header_footer:
        is_chi = True
    if "CHI '1" in header_footer or "CHI '0" in header_footer:
        is_chi = True

    # Explicit check for simple "CHI" word if others fail?
    # No, risky.

    if is_ubicomp:
        is_chi = False

    if is_chi:
        count = get_citations(fn[:-4], citations)
        total_chi += count
        results.append({"title": fn, "count": count})
    else:
        results.append({"title": fn, "status": "NOT CHI"})

print("__RESULT__:")
print(json.dumps({"results": results, "total": total_chi}))
